const item = $json;

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function toBool(value) {
  if (value === true || value === "true" || value === 1 || value === "1") return true;
  return false;
}

const videoId = String(item.video_id || "").trim();

if (!videoId) {
  return {
    json: {
      ...item,
      valid: false,
      invalid_reason: "missing_video_id"
    }
  };
}

const views = toNumber(item.views);
const likes = toNumber(item.likes);
const comments = toNumber(item.comments);
const shares = toNumber(item.shares);

const sellPrice = toNumber(item.sell_price);
const productCost = toNumber(item.product_cost);
const shippingCost = toNumber(item.shipping_cost, 4.5);

const createdAtRaw = item.created_at || item.posted_at || item.publish_time;
const createdAt = createdAtRaw ? new Date(createdAtRaw) : null;
const now = new Date();

let hoursSincePost = 24;
if (createdAt && !Number.isNaN(createdAt.getTime())) {
  hoursSincePost = Math.max((now - createdAt) / 1000 / 60 / 60, 1);
}

return {
  json: {
    ...item,
    video_id: videoId,
    title: String(item.title || "").trim(),
    author: String(item.author || "").trim(),
    views,
    likes,
    comments,
    shares,
    sell_price: sellPrice,
    product_cost: productCost,
    shipping_cost: shippingCost,
    same_product_count: toNumber(item.same_product_count),
    comment_buy_intent_count: toNumber(item.comment_buy_intent_count),
    creator_count: toNumber(item.creator_count),
    has_product_link: toBool(item.has_product_link),
    supplier_available: toBool(item.supplier_available),
    hours_since_post: hoursSincePost,
    valid: true,
    invalid_reason: null
  }
};

const views = Number($json.views || 0);
const likes = Number($json.likes || 0);
const comments = Number($json.comments || 0);
const shares = Number($json.shares || 0);
const hours = Math.max(Number($json.hours_since_post || 24), 1);

const likeRate = likes / Math.max(views, 1);
const commentRate = comments / Math.max(views, 1);
const shareRate = shares / Math.max(views, 1);

const velocity = views / hours;

let viralScore =
  velocity * 0.0004 +
  shareRate * 3500 +
  commentRate * 2500 +
  likeRate * 300;

viralScore = Math.min(100, Math.max(0, viralScore));
viralScore = Math.round(viralScore * 100) / 100;

let viralLevel = "LOW";

if (viralScore >= 80) {
  viralLevel = "EXPLOSIVE";
} else if (viralScore >= 70) {
  viralLevel = "HIGH";
} else if (viralScore >= 50) {
  viralLevel = "MEDIUM";
}

return {
  json: {
    ...$json,
    like_rate: Math.round(likeRate * 10000) / 10000,
    comment_rate: Math.round(commentRate * 10000) / 10000,
    share_rate: Math.round(shareRate * 10000) / 10000,
    velocity: Math.round(velocity * 100) / 100,
    viral_score: viralScore,
    viral_level: viralLevel
  }
};

const views = Number($json.views || 0);
const likes = Number($json.likes || 0);
const comments = Number($json.comments || 0);
const shares = Number($json.shares || 0);

const likeRate = Number($json.like_rate || likes / Math.max(views, 1));
const commentRate = Number($json.comment_rate || comments / Math.max(views, 1));
const shareRate = Number($json.share_rate || shares / Math.max(views, 1));

let score = 0;

if (views >= 100000) score += 25;
else if (views >= 50000) score += 20;
else if (views >= 10000) score += 15;
else if (views >= 3000) score += 10;
else if (views >= 1000) score += 5;

if (likeRate >= 0.08) score += 25;
else if (likeRate >= 0.05) score += 20;
else if (likeRate >= 0.03) score += 15;
else if (likeRate >= 0.015) score += 8;

if (commentRate >= 0.01) score += 20;
else if (commentRate >= 0.005) score += 15;
else if (commentRate >= 0.002) score += 8;

if (shareRate >= 0.01) score += 20;
else if (shareRate >= 0.005) score += 15;
else if (shareRate >= 0.002) score += 8;

if (($json.title || "").length >= 8) score += 10;

score = Math.min(100, score);

let scoreLevel = "LOW";
if (score >= 75) scoreLevel = "HIGH";
else if (score >= 60) scoreLevel = "MEDIUM";

return {
  json: {
    ...$json,
    score,
    score_level: scoreLevel
  }
};

const sellPrice = Number($json.sell_price || 0);
const productCost = Number($json.product_cost || 0);
const shippingCost = Number($json.shipping_cost || 4.5);
const feeRate = Number($json.platform_fee_rate || 0.08);
const adCost = Number($json.ad_cost_estimate || 0);

const platformFee = sellPrice * feeRate;
const grossProfit = sellPrice - productCost - shippingCost - platformFee;
const netProfit = grossProfit - adCost;
const marginRate = sellPrice > 0 ? netProfit / sellPrice : 0;

let profitScore = 0;

if (sellPrice <= 0 || productCost <= 0) {
  profitScore = 0;
} else if (marginRate >= 0.5) {
  profitScore = 100;
} else if (marginRate >= 0.4) {
  profitScore = 85;
} else if (marginRate >= 0.3) {
  profitScore = 70;
} else if (marginRate >= 0.2) {
  profitScore = 50;
} else if (marginRate >= 0.1) {
  profitScore = 30;
} else {
  profitScore = 10;
}

let profitLevel = "LOW";
if (profitScore >= 80) profitLevel = "HIGH";
else if (profitScore >= 60) profitLevel = "MEDIUM";

return {
  json: {
    ...$json,
    platform_fee: Math.round(platformFee * 100) / 100,
    gross_profit: Math.round(grossProfit * 100) / 100,
    net_profit: Math.round(netProfit * 100) / 100,
    margin_rate: Math.round(marginRate * 10000) / 10000,
    profit_score: profitScore,
    profit_level: profitLevel
  }
};

const baseScore = Number($json.score || 0);
const viralScore = Number($json.viral_score || 0);
const commercialScore = Number($json.commercial_score || 0);
const profitScore = Number($json.profit_score || 0);
const netProfit = Number($json.net_profit || 0);

const minNetProfit = 8;

const finalScore =
  baseScore * 0.2 +
  viralScore * 0.25 +
  commercialScore * 0.25 +
  profitScore * 0.3;

let decision = "REJECTED";
let reasons = [];

if (baseScore >= 60) reasons.push("base_score_pass");
if (viralScore >= 70) reasons.push("viral_pass");
if (commercialScore >= 50) reasons.push("commercial_pass");
if (profitScore >= 60) reasons.push("profit_pass");
if (netProfit >= minNetProfit) reasons.push("net_profit_pass");

if (
  finalScore >= 75 &&
  profitScore >= 60 &&
  commercialScore >= 50 &&
  netProfit >= minNetProfit &&
  (baseScore >= 60 || viralScore >= 70)
) {
  decision = "WINNER";
} else if (
  finalScore >= 55 &&
  profitScore >= 40 &&
  netProfit > 0 &&
  (commercialScore >= 35 || viralScore >= 70)
) {
  decision = "WATCHLIST";
}

let action = "ignore";

if (decision === "WINNER") {
  action = "prepare_product_test";
} else if (decision === "WATCHLIST") {
  action = "monitor_or_manual_review";
}

return {
  json: {
    ...$json,
    final_score: Math.round(finalScore * 100) / 100,
    decision,
    selected: decision === "WINNER",
    winner_reason: reasons.join(","),
    next_action: action,
    updated_at: new Date().toISOString()
  }
};

const hasProductLink = $json.has_product_link === true;
const sameProductCount = Number($json.same_product_count || 0);
const buyIntent = Number($json.comment_buy_intent_count || 0);
const creatorCount = Number($json.creator_count || 0);
const supplierAvailable = $json.supplier_available === true;

let commercialScore = 0;
let reasons = [];

if (hasProductLink) {
  commercialScore += 25;
  reasons.push("has_product_link");
}

if (sameProductCount >= 5) {
  commercialScore += 25;
  reasons.push("many_same_product_videos");
} else if (sameProductCount >= 3) {
  commercialScore += 18;
  reasons.push("some_same_product_videos");
}

if (buyIntent >= 20) {
  commercialScore += 25;
  reasons.push("strong_comment_buy_intent");
} else if (buyIntent >= 5) {
  commercialScore += 18;
  reasons.push("comment_buy_intent");
}

if (creatorCount >= 5) {
  commercialScore += 15;
  reasons.push("multiple_creators");
} else if (creatorCount >= 3) {
  commercialScore += 10;
  reasons.push("some_creators");
}

if (supplierAvailable) {
  commercialScore += 20;
  reasons.push("supplier_available");
}

commercialScore = Math.min(100, commercialScore);

let commercialLevel = "LOW";
if (commercialScore >= 75) commercialLevel = "HIGH";
else if (commercialScore >= 50) commercialLevel = "MEDIUM";

return {
  json: {
    ...$json,
    commercial_score: commercialScore,
    commercial_level: commercialLevel,
    commercial_reasons: reasons.join(",")
  }
};

return {
  json: {
    ...$json,
    commercial_score: $json.commercial_score || 0,
    profit_score: $json.profit_score || 0,
    final_score: $json.final_score || 0,
    decision: "REJECTED",
    selected: false,
    winner_reason: "failed_score_and_viral_filter",
    updated_at: new Date().toISOString()
  }
};

if (!$json.video_id) {
  throw new Error("Missing video_id");
}

if (!$json.decision) {
  throw new Error("Missing decision");
}

// 数值清洗
const cleanNumber = (v) => (isNaN(Number(v)) ? 0 : Number(v));

return {
  json: {
    ...$json,
    views: cleanNumber($json.views),
    likes: cleanNumber($json.likes),
    comments: cleanNumber($json.comments),
    shares: cleanNumber($json.shares),
    final_score: cleanNumber($json.final_score),
    updated_at: $json.updated_at || new Date().toISOString()
  }
};

if (!$json.video_id) {
  throw new Error("Missing video_id");
}

if (!$json.decision) {
  throw new Error("Missing decision");
}

// 数值清洗
const cleanNumber = (v) => (isNaN(Number(v)) ? 0 : Number(v));

return {
  json: {
    ...$json,
    views: cleanNumber($json.views),
    likes: cleanNumber($json.likes),
    comments: cleanNumber($json.comments),
    shares: cleanNumber($json.shares),
    final_score: cleanNumber($json.final_score),
    updated_at: $json.updated_at || new Date().toISOString()
  }
};

if (!$json.video_id) {
  throw new Error("Missing video_id");
}

if (!["WINNER", "WATCHLIST", "REJECTED"].includes($json.decision)) {
  throw new Error("Invalid decision: " + $json.decision);
}

return {
  json: {
    ...$json,
    updated_at: $json.updated_at || new Date().toISOString()
  }
};

if (!$json.video_id) {
  throw new Error("Missing video_id");
}

if (!$json.decision) {
  throw new Error("Missing decision");
}

// 数值清洗
