return {
  json: {
    ...$json,
    views: cleanNumber($json.views),
    likes: cleanNumber($json.likes),
    comments: cleanNumber($json.comments),
    shares: cleanNumber($json.shares),
    final_score: cleanNumber($json.final_score),
    updated_at: $json.updated_at || new Date().toISOString()
  }
};

return {
  json: {
    ...$json,
    commercial_score: $json.commercial_score || 0,
    profit_score: $json.profit_score || 0,
    final_score: $json.final_score || 0,
    decision: "REJECTED",
    selected: false,
    winner_reason: "failed_score_and_viral_filter",
    updated_at: new Date().toISOString()
  }
};
